def cargar_tipos_doc_personalizados(archivo):
    """Lee informe de tipos de documentos del cliente y retorna set de códigos."""
    try:
        df = pd.read_excel(archivo, header=3, engine='openpyxl')
        df.columns = ['Codigo','Descripcion']
        df = df.dropna(subset=['Codigo'])
        codigos = set(df['Codigo'].astype(str).str.strip().str.upper().tolist())
        codigos = {c for c in codigos if 1 <= len(c) <= 4}
        return codigos
    except:
        return set()

def tiene_caracteres_especiales(v):
    return bool(re.search(r'[^0-9\s]', str(v).strip())) if str(v).strip() not in ('', 'nan', 'None') else False

def es_numerico(v):
    try: float(str(v).replace(',', '').strip()); return True
    except: return False

def es_fecha_valida(v):
    s = str(v).strip()
    if s in ('', 'nan', 'None'): return False
    for fmt in ('%d/%m/%Y', '%Y-%m-%d', '%d-%m-%Y', '%Y/%m/%d'):
        try: datetime.strptime(s.split(' ')[0], fmt); return True
        except: pass
    return False

def limpiar_nit(v):
    try: return str(int(float(str(v).replace(',','').strip().lstrip("'"))))
    except: return str(v).strip().lstrip("'")

def fmt_num(v):
    try: return f"{float(v):,.2f}"
    except: return str(v)

