def validar_saldos_iniciales(df, nits_validos=None):
    """Retorna lista de errores con (fila, columna, tipo, mensaje_simple, mensaje_tecnico)"""
    errores = []
    total_deb = 0.0
    total_cre = 0.0

    for idx, row in df.iterrows():
        fila = idx + 2  # +2 porque fila 1 es encabezado
        cuenta  = str(row.get('Cuenta Contable', '')).strip().lstrip("'")
        nit     = str(row.get('NIT', '')).strip().lstrip("'")
        cc      = str(row.get('Centro Costos', '')).strip().lstrip("'")
        debito  = row.get('Débito', '')
        credito = row.get('Crédito', '')

        # Saltar filas sin cuenta ni NIT (filas de totales o vacías)
        if cuenta in ('', 'nan', 'None') and nit in ('', 'nan', 'None'):
            continue

        # ── Cuenta Contable ──
        if cuenta in ('', 'nan', 'None'):
            errores.append((fila, 'Cuenta Contable', 'formato',
                '❌ La columna Cuenta Contable está vacía.',
                'Campo vacío — se espera código de cuenta auxiliar.'))
        elif tiene_caracteres_especiales(cuenta):
            errores.append((fila, 'Cuenta Contable', 'formato',
                f'❌ La Cuenta Contable "{cuenta}" tiene letras o símbolos. Solo se permiten números.',
                'Contiene caracteres especiales.'))
        elif not es_numerico(cuenta):
            errores.append((fila, 'Cuenta Contable', 'formato',
                f'❌ La Cuenta Contable "{cuenta}" no es un número válido.',
                'No numérico.'))

        # ── NIT ──
        if nit not in ('', 'nan', 'None') and nits_validos is not None:
            nit_limpio = limpiar_nit(nit)
            if nit_limpio not in nits_validos:
                errores.append((fila, 'NIT', 'logica',
                    f'⚠️ El NIT "{nit}" no está en el maestro de terceros. Verifique que esté bien escrito.',
                    'Tercero no registrado en el sistema.'))

        # ── Centro de Costos ──
        if cc not in ('', 'nan', 'None') and tiene_caracteres_especiales(cc):
            errores.append((fila, 'Centro Costos', 'formato',
                f'❌ El Centro de Costos "{cc}" tiene letras o símbolos. Solo se permiten números.',
                'Contiene caracteres especiales.'))

        # ── Débito ──
        deb_val = pd.to_numeric(str(debito).replace(',',''), errors='coerce')
        if pd.isna(deb_val):
            if str(debito).strip() in ('', 'nan', 'None'):
                errores.append((fila, 'Débito', 'formato',
                    '❌ La columna Débito está vacía. Ingrese 0 si no tiene valor.',
                    'Campo vacío — requerido.'))
            else:
                errores.append((fila, 'Débito', 'formato',
                    f'❌ El valor de Débito "{debito}" no es un número válido.',
                    'No es un valor decimal.'))
        else:
            total_deb += deb_val

        # ── Crédito ──
        cre_val = pd.to_numeric(str(credito).replace(',',''), errors='coerce')
        if pd.isna(cre_val):
            if str(credito).strip() in ('', 'nan', 'None'):
                errores.append((fila, 'Crédito', 'formato',
                    '❌ La columna Crédito está vacía. Ingrese 0 si no tiene valor.',
                    'Campo vacío — requerido.'))
            else:
                errores.append((fila, 'Crédito', 'formato',
                    f'❌ El valor de Crédito "{credito}" no es un número válido.',
                    'No es un valor decimal.'))
        else:
            total_cre += cre_val

    # ── Validación de balance Débitos = Créditos ──
    diferencia = round(total_deb - total_cre, 2)
    if abs(diferencia) > 0.01:
        errores.append((None, 'Balance', 'general',
            f'❌ La suma de Débitos (${fmt_num(total_deb)}) es diferente a la suma de Créditos (${fmt_num(total_cre)}). '
            f'La diferencia es ${fmt_num(diferencia)}. Revise los valores ingresados.',
            f'Sumatoria Débitos ≠ Créditos. Diferencia: {diferencia:,.2f}'))

    return errores, total_deb, total_cre


def validar_movimientos(df, nits_validos=None, tipos_doc_validos=None, rangos_consecutivos=None):
    errores = []
    consecutivos_vistos = {}

    for idx, row in df.iterrows():
        fila = idx + 2
        cuenta  = str(row.get('Cuenta Contable', '')).strip().lstrip("'")
        nit     = str(row.get('NIT', '')).strip().lstrip("'")
        cc      = str(row.get('Centro Costos', '')).strip().lstrip("'")
        fecha   = row.get('Fecha del documento', '')
        tipo_doc= str(row.get('Tipo documento', '')).strip()
        consec  = str(row.get('Consecutivo', '')).strip()
        debito  = row.get('Débito', '')
        credito = row.get('Crédito', '')
        sucursal= str(row.get('Sucursal', '')).strip()
        tasa    = row.get('Tasa de cambio', '')

        # Saltar filas sin cuenta (vacías o totales)
        if cuenta in ('', 'nan', 'None'):
            continue

        # ── Cuenta Contable ──
        if cuenta in ('', 'nan', 'None'):
            errores.append((fila, 'Cuenta Contable', 'formato',
                '❌ La columna Cuenta Contable está vacía.',
                'Campo vacío.'))
        elif tiene_caracteres_especiales(cuenta):
            errores.append((fila, 'Cuenta Contable', 'formato',
                f'❌ La Cuenta Contable "{cuenta}" tiene letras o símbolos. Solo se permiten números.',
                'Contiene caracteres especiales.'))
        elif not es_numerico(cuenta):
            errores.append((fila, 'Cuenta Contable', 'formato',
                f'❌ La Cuenta Contable "{cuenta}" no es un número válido.',
                'No numérico.'))

        # ── NIT ──
        if nit not in ('', 'nan', 'None') and nits_validos is not None:
            nit_limpio = limpiar_nit(nit)
            if nit_limpio not in nits_validos:
                errores.append((fila, 'NIT', 'logica',
                    f'⚠️ El NIT "{nit}" no está en el maestro de terceros.',
                    'Tercero no registrado.'))

        # ── Centro de Costos ──
        if cc not in ('', 'nan', 'None') and tiene_caracteres_especiales(cc):
            errores.append((fila, 'Centro Costos', 'formato',
                f'❌ El Centro de Costos "{cc}" tiene caracteres no permitidos.',
                'Contiene caracteres especiales.'))

        # ── Fecha ──
        if str(fecha).strip() in ('', 'nan', 'None'):
            errores.append((fila, 'Fecha del documento', 'formato',
                '❌ La Fecha del documento está vacía. Use el formato dd/mm/aaaa.',
                'Campo vacío.'))
        elif not es_fecha_valida(fecha):
            errores.append((fila, 'Fecha del documento', 'formato',
                f'❌ La fecha "{fecha}" no tiene el formato correcto. Use dd/mm/aaaa.',
                'Formato de fecha inválido.'))

        # ── Tipo documento ──
        if tipo_doc in ('', 'nan', 'None'):
            errores.append((fila, 'Tipo documento', 'formato',
                '❌ El Tipo de documento está vacío.',
                'Campo vacío.'))
        elif tipos_doc_validos and tipo_doc.upper().strip() not in tipos_doc_validos:
            errores.append((fila, 'Tipo documento', 'logica',
                f'⚠️ El tipo de documento "{tipo_doc}" no está registrado en el sistema. '
                f'Verifique que sea correcto o suba el informe de tipos de documentos si tiene tipos personalizados.',
                'Tipo de documento no registrado en el sistema.'))

        # ── Consecutivo ──
        if consec in ('', 'nan', 'None'):
            errores.append((fila, 'Consecutivo', 'formato',
                '❌ El Consecutivo está vacío.',
                'Campo vacío.'))
        else:
            try:
                c_int = int(float(consec))
                if c_int < 1 or c_int > 2147000000:
                    errores.append((fila, 'Consecutivo', 'formato',
                        f'❌ El Consecutivo {c_int} está fuera del rango permitido (1 a 2,147,000,000).',
                        'Fuera del rango 1 a 2147000000.'))
                elif str(consec).strip().startswith('0'):
                    errores.append((fila, 'Consecutivo', 'formato',
                        f'❌ El Consecutivo "{consec}" no puede empezar por 0.',
                        'Inicia con dígito 0.'))
                else:
                    clave = f"{tipo_doc}_{consec}"
                    if clave in consecutivos_vistos:
                        errores.append((fila, 'Consecutivo', 'formato',
                            f'❌ El Consecutivo {consec} para el tipo "{tipo_doc}" está repetido '
                            f'(también aparece en la fila {consecutivos_vistos[clave]}).',
                            'Consecutivo duplicado.'))
                    else:
                        consecutivos_vistos[clave] = fila
                        # MO-20: Verificar consecutivo contra rangos registrados en el sistema
                        if rangos_consecutivos:
                            rango_ocupado = esta_en_rango_consecutivo(c_int, tipo_doc, rangos_consecutivos)
                            if rango_ocupado:
                                errores.append((fila, 'Consecutivo', 'logica',
                                    f'❌ El consecutivo {c_int} del tipo "{tipo_doc}" ya está '
                                    f'registrado en el sistema (rango ocupado: '
                                    f'{rango_ocupado[0]} → {rango_ocupado[1]}). '
                                    f'Use un consecutivo fuera de ese rango.',
                                    f'Consecutivo ya en sistema. Rango: {rango_ocupado[0]}-{rango_ocupado[1]}'))
            except:
                errores.append((fila, 'Consecutivo', 'formato',
                    f'❌ El Consecutivo "{consec}" no es un número válido.',
                    'No es entero válido.'))

        # ── Débito ──
        deb_val = pd.to_numeric(str(debito).replace(',',''), errors='coerce')
        if pd.isna(deb_val):
            errores.append((fila, 'Débito', 'formato',
                '❌ El valor de Débito está vacío o no es un número.',
                'Campo vacío o no decimal.'))

        # ── Crédito ──
        cre_val = pd.to_numeric(str(credito).replace(',',''), errors='coerce')
        if pd.isna(cre_val):
            errores.append((fila, 'Crédito', 'formato',
                '❌ El valor de Crédito está vacío o no es un número.',
                'Campo vacío o no decimal.'))

        # ── Sucursal ──
        if sucursal in ('', 'nan', 'None'):
            errores.append((fila, 'Sucursal', 'formato',
                '❌ La Sucursal está vacía. Si no sabe cuál es, use 0 (principal).',
                'Campo vacío.'))
        elif tiene_caracteres_especiales(sucursal):
            errores.append((fila, 'Sucursal', 'formato',
                f'❌ La Sucursal "{sucursal}" tiene caracteres no permitidos. Solo se permiten números.',
                'Contiene caracteres especiales.'))
        elif not es_numerico(sucursal):
            errores.append((fila, 'Sucursal', 'formato',
                f'❌ La Sucursal "{sucursal}" no es un número válido.',
                'No numérico.'))

        # ── Tasa de cambio ──
        if str(tasa).strip() not in ('', 'nan', 'None', '0'):
            tasa_val = pd.to_numeric(str(tasa).replace(',',''), errors='coerce')
            if pd.isna(tasa_val):
                errores.append((fila, 'Tasa de cambio', 'formato',
                    f'❌ La Tasa de cambio "{tasa}" no es un número válido.',
                    'No es un valor decimal.'))

    # Advertencias del sistema
    advertencias = [
        '⚠️ El sistema verificará al importar: que la Cuenta Contable sea tipo auxiliar.',
        '⚠️ El sistema verificará al importar: que los Consecutivos no estén ya registrados (si no cargó el informe de verificación, esta validación se hace al importar).',
        '⚠️ El sistema verificará al importar: que la Sucursal sea administrativa.',
    ]

    return errores, advertencias


def leer_plantilla(archivo, tipo):
    """Lee plantilla y retorna DataFrame o error."""
    try:
        df = pd.read_excel(archivo, sheet_name='MIGRACION', header=0, engine='openpyxl',
                           keep_default_na=False, na_values=[''])
        if tipo == 'si':
            cols_req = ['Cuenta Contable', 'NIT', 'Centro Costos', 'Débito', 'Crédito']
        else:
            cols_req = ['Fecha del documento', 'Tipo documento', 'Consecutivo',
                        'Cuenta Contable', 'Centro Costos', 'NIT', 'Débito', 'Crédito', 'Sucursal']
        faltantes = [c for c in cols_req if c not in df.columns]
        if faltantes:
            return None, f"Faltan columnas obligatorias: {', '.join(faltantes)}"
        # Filtrar filas completamente vacías
        df = df.dropna(how='all').reset_index(drop=True)
        return df, None
    except Exception as e:
        return None, f"Error al leer el archivo: {str(e)}"


def render_resultado(errores, nombre_libro, tipo, total_deb=None, total_cre=None, advertencias=None):
    """Renderiza el resultado de validación de una plantilla."""
    errores_reales = [e for e in errores if e[0] is not None or e[1] == 'Balance']
    balance_err    = [e for e in errores if e[1] == 'Balance']
    fila_errs      = [e for e in errores if e[0] is not None]

    total = len(fila_errs) + len(balance_err)

    if total == 0:
        st.markdown(f'<div class="ok-box">✅ <b>¡Plantilla {nombre_libro} lista!</b> No se encontraron errores. Puede continuar con la importación.</div>', unsafe_allow_html=True)
    else:
        st.markdown(f'<div class="err-box">❌ Se encontraron <b>{total} problema(s)</b> en la plantilla <b>{nombre_libro}</b> que deben corregirse antes de importar.</div>', unsafe_allow_html=True)

    # Métricas rápidas
    if tipo == 'si' and total_deb is not None:
        c1, c2, c3 = st.columns(3)
        with c1:
            color = 'green' if abs(total_deb - total_cre) < 0.01 else 'red'
            st.markdown(f'<div class="card {color}"><div class="card-label">SUMA DÉBITOS</div><div class="card-value">${fmt_num(total_deb)}</div></div>', unsafe_allow_html=True)
        with c2:
            st.markdown(f'<div class="card {color}"><div class="card-label">SUMA CRÉDITOS</div><div class="card-value">${fmt_num(total_cre)}</div></div>', unsafe_allow_html=True)
        with c3:
            dif = total_deb - total_cre
            st.markdown(f'<div class="card {color}"><div class="card-label">DIFERENCIA</div><div class="card-value">${fmt_num(dif)}</div><div class="card-sub">{"✅ Cuadra" if abs(dif) < 0.01 else "❌ No cuadra"}</div></div>', unsafe_allow_html=True)

    if total == 0:
        return

    # Agrupar errores por columna
    st.markdown("#### 📋 Detalle de errores")

    # Error de balance primero (es general)
    for e in balance_err:
        st.markdown(f'''<div class="error-row">
            <span class="error-tag-general">BALANCE</span>
            <div><b>Toda la plantilla</b><br><span style="color:#374151;font-size:13px">{e[3]}</span></div>
        </div>''', unsafe_allow_html=True)

    # Errores por fila agrupados
    if fila_errs:
        cols_con_errores = sorted(set(e[1] for e in fila_errs))
        for col in cols_con_errores:
            errs_col = [e for e in fila_errs if e[1] == col]
            with st.expander(f"📌 {col} — {len(errs_col)} error(es)", expanded=len(errs_col) <= 5):
                for e in errs_col:
                    tag_tipo = e[2]
                    tag_html = {
                        'formato': '<span class="error-tag-formato">FORMATO</span>',
                        'logica':  '<span class="error-tag-logica">LÓGICA</span>',
                        'general': '<span class="error-tag-general">GENERAL</span>',
                    }.get(tag_tipo, '')
                    fila_txt = f'Fila {e[0]}' if e[0] else 'General'
                    st.markdown(f'''<div class="error-row">
                        {tag_html}
                        <div><b style="color:{C_MID}">{fila_txt}</b> &nbsp;
                        <span style="color:#374151;font-size:13px">{e[3]}</span></div>
                    </div>''', unsafe_allow_html=True)

    # Advertencias del sistema
    if advertencias:
        st.markdown("#### ℹ️ Validaciones que confirma el sistema al importar")
        for adv in advertencias:
            st.markdown(f'<div class="warn-box">{adv}</div>', unsafe_allow_html=True)


def exportar_excel_errores(plantillas_resultados):
    """Genera Excel con todos los errores para que el cliente corrija."""
    out = BytesIO()
    with pd.ExcelWriter(out, engine='openpyxl') as writer:
        for nombre, errores, df_orig in plantillas_resultados:
            rows = []
            for e in errores:
                rows.append({
                    'Fila en plantilla': e[0] if e[0] else 'General',
                    'Columna': e[1],
                    'Tipo': e[2].capitalize(),
                    'Qué debe corregir': e[3].replace('❌','').replace('⚠️','').strip(),
                })
            if rows:
                df_err = pd.DataFrame(rows)
                sheet = nombre[:31]
                df_err.to_excel(writer, sheet_name=sheet, index=False)
                ws = writer.sheets[sheet]
                ws.column_dimensions['A'].width = 18
                ws.column_dimensions['B'].width = 22
                ws.column_dimensions['C'].width = 12
                ws.column_dimensions['D'].width = 80
    return out.getvalue()



def parsear_informe_consecutivos(archivo):
    """Parsea el informe de Verificación de Consecutivos del sistema SINCO.
    Retorna dict: sigla_tipo_doc → lista de (consecutivo_inicial, consecutivo_final)
    Incluye rango principal, anulados y no contabilizados (todos ocupan el consecutivo).
    Tipos no homologables se guardan con su nombre completo normalizado como clave.
    """
    import unicodedata

    def _norm(s):
        s = str(s).strip().upper()
        s = unicodedata.normalize('NFD', s)
        return ''.join(c for c in s if unicodedata.category(c) != 'Mn')

    CATALOGO_DESC_SIGLA = {
        'COMPROBANTE DE EGRESO REVERSADO':'AE','AJUSTES POR INFLACION':'AI',
        'AJUSTES Y RECLASIFICACIONES':'AJ','AJUSTE DIFERENCIA EN CAMBIO':'AM',
        'ARRAS':'AR','DOCUMENTO SOPORTE REVERSADO':'AS','BAJA DE ACTIVOS':'BA',
        'NOTA CREDITO INMB. ADMINISTRADA':'C5','CIERRE ANUAL':'CA',
        'COMPROBANTE DE DIARIO':'CD','COMPROBANTE DE EGRESO':'CE',
        'CHEQUES POSFECHADOS':'CH','COMPROBANTE DE INGRESO':'CI',
        'CAUSACION MASIVA ENTRADAS SIN FACTURA':'CM','CUENTA POR PAGAR':'CP',
        'NOTA DEBITO INMB. ADMINISTRADA':'D5','DEPRECIACION':'DA',
        'DEVOLUCION CHEQUE':'DC','ABR DESEMBOLSO DE PRESTAMOS PROPIETARIOS':'DS',
        'DEVOLUCION O CANJE FACTURA':'DV','FACTURACION ANTICIPADA':'FA',
        'FACTURACION DIARIA':'FD','FACTURA DE VENTA':'FV',
        'GASTOS BANCARIOS AUTOMATICOS':'GA','GASTOS BANCARIOS':'GB',
        'GASTOS BANCARIOS MANUALES':'GM','AJUSTE POR INFLACION':'IC',
        'AJUSTE POR INFLACION DE LA DEPRECIACION':'ID',
        'INSTRUMENTOS FINANCIEROS':'IF',
        'COMPROBANTE DE LEGALIZACION INCAPACIDADES':'LI',
        'CAJA CHICA':'MC','MIGRACION FACTURAS':'MF',
        'ABR - MANTENIMIENTO DE INMUEBLES':'MI','AJUSTE MULTIMONEDA':'MM',
        'ABR - AJUSTES':'N1','ABR - AJUSTES ANTICIPADOS':'N2',
        'ABR - PAGOS ARRENDATARIOS POR CRUZAR':'N3','ABR - NOTAS CONTABLES':'N4',
        'NOTA CREDITO':'NC','NOTA DEBITO':'ND','NOMINA POR PAGAR':'NP',
        'DESEMBOLSO CAPITAL OB. FIN.':'OB','INTERESES OB. FIN.':'OI',
        'PRORRATAS OB. FIN.':'OP','RECLASIFICACION Y REVERSION OB. FIN.':'OR',
        'SUBROGACIONES OB. FIN.':'OS','UVR OB. FIN.':'OU',
        'ABONO CAPITAL PAT. AUT.':'PA','PARTIDAS CONCILIATORIAS INICIALES':'PD',
        'PAGO INTERESES PAT. AUT.':'PI','PROVISION NOMINA':'PM',
        'ABR - COBRO CUENTAS PROPIAS':'PP','ABR - PAGOS A TERCEROS':'PT',
        'RECIBO INMOBILIARIO ADMINISTRADO':'RA','RECIBO DE CAJA':'RC',
        'REEMBOLSABLES':'RE','REVERSION SALDOS MIGRADOS':'RM',
        'RESOLUCION DEL NEGOCIO':'RN','DOCUMENTO DE CARTERA REVERSADO':'RR',
        'REVALUACION ACTIVOS':'RV','SALIDAS ALMACEN':'SA',
        'SALDOS INICIALES':'SI','ABR DESCUENTO SERVICIOS PUBLICOS AL PROPIETARIO':'SP',
        'TRASLADO DE ANTICIPOS':'TA','TRASLADOS DE COSTOS':'TC',
        'CONSIGNACION':'TD','TRASLADO DE FONDOS':'TF','TRASLADO PRODUCTO':'TP',
        'NOTA EN VALOR':'VD','VALOR RESIDUAL':'VR'
    }
    DESC_A_SIGLA = {_norm(k): v for k, v in CATALOGO_DESC_SIGLA.items()}

    def _homologar(nombre):
        """Retorna sigla si es estándar, o nombre normalizado si es personalizado."""
        n = _norm(nombre)
        if n in DESC_A_SIGLA:
            return DESC_A_SIGLA[n]
        # Búsqueda parcial
        matches = [s for d, s in DESC_A_SIGLA.items() if n in d or d in n]
        return matches[0] if matches else n  # fallback: nombre normalizado

    def _es_numero(v):
        try: int(float(str(v).replace(',',''))); return True
        except: return False

    SKIP_META = {'CONSECUTIVO INICIAL', 'PRINCIPAL', 'FISCAL', 'NIF'}

    try:
        df = pd.read_excel(archivo, sheet_name=0, header=None, dtype=str)
    except Exception:
        return {}

    rangos = {}       # clave_tipo → [(ini, fin), ...]
    tipo_actual = None
    esperando_rango = False

    for _, row in df.iterrows():
        vals = [str(v).strip() for v in row.tolist()
                if str(v).strip() not in ('', 'nan', 'None', ' ')]
        if not vals:
            continue

        primera_norm = _norm(vals[0])

        # Saltar metadatos del encabezado
        if any(primera_norm.startswith(_norm(k)) for k in SKIP_META):
            continue

        # Detectar header de rango "Consecutivo inicial | Consecutivo final"
        if primera_norm == 'CONSECUTIVO INICIAL':
            esperando_rango = True
            continue

        # Detectar secciones secundarias — NO saltarlas, siguen acumulando rangos
        # "Documentos anulados" y "Documentos no contabilizados" generan rangos igualmente
        if primera_norm in ('DOCUMENTOS ANULADOS', 'DOCUMENTOS NO CONTABILIZADOS'):
            esperando_rango = False  # Los rangos vienen en filas siguientes sin header
            continue

        nums = [v for v in vals if _es_numero(v)]

        # Fila de rangos numéricos
        if len(nums) >= 2:
            i = 0
            while i + 1 < len(nums):
                try:
                    ini = int(float(nums[i].replace(',','')))
                    fin = int(float(nums[i+1].replace(',','')))
                    if tipo_actual and ini <= fin:
                        rangos.setdefault(tipo_actual, []).append((ini, fin))
                except Exception:
                    pass
                i += 2
            esperando_rango = False
            continue

        # Fila de un solo número (ej: "Documentos no contabilizados" con 1 elemento)
        if len(nums) == 1 and tipo_actual:
            try:
                v = int(float(nums[0].replace(',','')))
                rangos.setdefault(tipo_actual, []).append((v, v))
            except Exception:
                pass
            continue

        # Fila de texto sin números → nombre de tipo de documento
        if len(nums) == 0 and len(vals) == 1:
            tipo_actual = _homologar(vals[0])
            esperando_rango = False
            continue

    return rangos


def esta_en_rango_consecutivo(consecutivo, tipo_sigla, rangos_map):
    """Verifica si un consecutivo está ocupado en el sistema.
    Retorna (ini, fin) del rango donde cae, o None si está libre.
    """
    try:
        c = int(float(str(consecutivo).replace(',','')))
    except Exception:
        return None
    for ini, fin in rangos_map.get(tipo_sigla.strip().upper(), []):
        if ini <= c <= fin:
            return (ini, fin)
    return None

def exportar_plantilla_marcada(archivo_original, errores, nombre_libro):
    """Genera copia de la plantilla con celdas en error resaltadas en rojo."""
    from openpyxl import load_workbook
    from openpyxl.styles import PatternFill, Font, Alignment, Border, Side
    from openpyxl.styles import PatternFill
    import copy

    ROJO_FILL   = PatternFill(start_color="FFCCCC", end_color="FFCCCC", fill_type="solid")
    ROJO_FONT   = Font(color="CC0000", bold=True)
    AMARILLO_FILL = PatternFill(start_color="FFF3CD", end_color="FFF3CD", fill_type="solid")
    AMARILLO_FONT = Font(color="856404")

    try:
        archivo_original.seek(0)
        wb = load_workbook(archivo_original)
        ws = wb['MIGRACION']

        # Obtener encabezados — fila 1
        headers = {}
        for cell in ws[1]:
            if cell.value:
                headers[str(cell.value).strip()] = cell.column

        # Errores con fila específica
        errores_fila = [(e[0], e[1], e[2], e[3]) for e in errores if e[0] is not None]

        # Marcar cada celda con error
        for fila_excel, columna, tipo, mensaje in errores_fila:
            col_idx = headers.get(columna)
            if col_idx:
                cell = ws.cell(row=fila_excel, column=col_idx)
                cell.fill = ROJO_FILL
                cell.font = ROJO_FONT
                # Agregar comentario con el mensaje
                from openpyxl.comments import Comment
                comentario = Comment(
                    mensaje.replace('❌','').replace('⚠️','').strip(),
                    'Validador SINCO A&F'
                )
                comentario.width  = 300
                comentario.height = 60
                cell.comment = comentario

        # Agregar hoja de resumen de errores
        if errores_fila:
            try: wb.remove(wb['⚠️ Errores'])
            except: pass
            ws_err = wb.create_sheet('⚠️ Errores')
            ws_err.append(['Fila', 'Columna', 'Tipo', 'Qué debe corregir'])
            # Estilo encabezado
            from openpyxl.styles import PatternFill as PF
            hdr_fill = PF(start_color="1B3A6B", end_color="1B3A6B", fill_type="solid")
            hdr_font = Font(color="FFFFFF", bold=True)
            for cell in ws_err[1]:
                cell.fill = hdr_fill
                cell.font = hdr_font
            for fila_excel, columna, tipo, mensaje in errores_fila:
                fill = ROJO_FILL if tipo == 'formato' else AMARILLO_FILL
                font = ROJO_FONT if tipo == 'formato' else AMARILLO_FONT
                row_cells = ws_err.append([
                    fila_excel, columna, tipo.capitalize(),
                    mensaje.replace('❌','').replace('⚠️','').strip()
                ])
                for cell in ws_err[ws_err.max_row]:
                    cell.fill = fill
                    cell.font = font
            ws_err.column_dimensions['A'].width = 8
            ws_err.column_dimensions['B'].width = 22
            ws_err.column_dimensions['C'].width = 12
            ws_err.column_dimensions['D'].width = 80

        out = BytesIO()
        wb.save(out)
        return out.getvalue()
    except Exception as ex:
        return None


