# ─────────────────────────────────────────────────────────────────────────────
# HELPERS
# ─────────────────────────────────────────────────────────────────────────────
def es_numerico(v):
    try: float(str(v).replace(',','').strip()); return True
    except: return False

def es_entero(v):
    try: int(float(str(v).replace(',','').strip())); return True
    except: return False

def tiene_caracteres_especiales_desc(v):
    """Detecta caracteres especiales no permitidos en descripciones."""
    return bool(re.search(r'[<>{}[\]\\|^~`]', str(v)))

def normalizar_codigo(v):
    """Normaliza código: quita decimales, espacios."""
    try: return str(int(float(str(v).replace(',','').strip().lstrip("'"))))
    except: return str(v).strip().lstrip("'")

def normalizar_depto(v):
    """Normaliza código de departamento a 2 dígitos con cero a la izquierda."""
    try: return str(int(float(str(v).strip()))).zfill(2)
    except: return str(v).strip()

def normalizar_ciudad(v):
    """Normaliza código de ciudad a 3 dígitos con cero a la izquierda."""
    try: return str(int(float(str(v).strip()))).zfill(3)
    except: return str(v).strip()

def es_email_valido(v):
    return bool(re.match(r'^[^@\s]+@[^@\s]+\.[^@\s]+$', str(v).strip()))

def calcular_dv(nit):
    """Calcula dígito de verificación de NIT colombiano."""
    try:
        nit_str = str(int(float(str(nit)))).zfill(15)
        factores = [71,67,59,53,47,43,41,37,29,23,19,17,13,7,3]
        suma = sum(int(d)*f for d, f in zip(nit_str, factores))
        residuo = suma % 11
        return 0 if residuo in (0,1) else 11 - residuo
    except: return None

def vacia(v):
    return str(v).strip() in ('', 'nan', 'None', 'NaN', '<NA>')

def leer_migracion(archivo):
    """Lee hoja MIGRACION de una plantilla."""
    try:
        df = pd.read_excel(archivo, sheet_name='MIGRACION', header=0,
                          engine='openpyxl', keep_default_na=False, na_values=[''])
        df = df.dropna(how='all').reset_index(drop=True)
        return df, None
    except Exception as e:
        return None, str(e)

def marcar_errores_excel(archivo_orig, errores, df_orig):
    """Genera copia de la plantilla con celdas en error resaltadas."""
    ROJO = PatternFill(start_color="FFCCCC", end_color="FFCCCC", fill_type="solid")
    FONT_ROJO = Font(color="CC0000", bold=True)
    AZUL_HDR  = PatternFill(start_color="1B3A6B", end_color="1B3A6B", fill_type="solid")
    FONT_BLANCO = Font(color="FFFFFF", bold=True)
    try:
        archivo_orig.seek(0)
        wb = load_workbook(archivo_orig)
        ws = wb['MIGRACION']
        headers = {str(cell.value).strip(): cell.column for cell in ws[1] if cell.value}
        for fila, columna, tipo, msg, _ in errores:
            if fila and columna in headers:
                cell = ws.cell(row=fila, column=headers[columna])
                cell.fill = ROJO; cell.font = FONT_ROJO
                try:
                    c = Comment(msg.replace('❌','').replace('⚠️','').strip(), 'Validador SINCO A&F')
                    c.width = 300; c.height = 70; cell.comment = c
                except: pass
        # Hoja resumen errores
        try: wb.remove(wb['⚠️ Errores'])
        except: pass
        ws_e = wb.create_sheet('⚠️ Errores')
        ws_e.append(['Fila','Columna','Tipo','Qué debe corregir'])
        for cell in ws_e[1]: cell.fill = AZUL_HDR; cell.font = FONT_BLANCO
        for fila, columna, tipo, msg, _ in errores:
            if fila:
                ws_e.append([fila, columna, tipo.capitalize(), msg.replace('❌','').replace('⚠️','').strip()])
        ws_e.column_dimensions['A'].width = 8
        ws_e.column_dimensions['B'].width = 25
        ws_e.column_dimensions['C'].width = 12
        ws_e.column_dimensions['D'].width = 90
        out = BytesIO(); wb.save(out); return out.getvalue()
    except: return None

# ─────────────────────────────────────────────────────────────────────────────
# VALIDADORES
# ─────────────────────────────────────────────────────────────────────────────

def validar_puc(df, es_fiscal=False, df_principal=None):
    """
    Valida PUC Principal o Fiscal.
    Retorna lista de (fila, columna, tipo, mensaje_simple, mensaje_tecnico)
    """
    errores = []
    codigos_vistos = {}
    equivalencias_vistas = {}
    codigos_maestros = set()

    # Primer paso: recolectar todos los maestros para validar jerarquía
    for idx, row in df.iterrows():
        cod = normalizar_codigo(row.get('Código',''))
        tipo = str(row.get('Tipo','')).strip().upper()
        if cod and tipo == 'M':
            codigos_maestros.add(cod)

    # Códigos del PUC Principal para validar equivalencias
    codigos_principal = set()
    if es_fiscal and df_principal is not None:
        for _, row in df_principal.iterrows():
            cod = normalizar_codigo(row.get('Código',''))
            if cod: codigos_principal.add(cod)

    for idx, row in df.iterrows():
        fila = idx + 2

        # Saltar filas completamente vacías
        vals = [str(v).strip() for v in row.tolist() if not vacia(v)]
        if not vals: continue

        cod        = normalizar_codigo(row.get('Código',''))
        desc       = str(row.get('Descripción','')).strip()
        tipo       = str(row.get('Tipo','')).strip().upper()
        req_cc     = str(row.get('Requiere Centro Costo','')).strip().upper()
        req_ter    = str(row.get('Requiere Tercero','')).strip().upper()
        req_base   = str(row.get('Requiere Base','')).strip().upper()
        pct        = row.get('%','')
        base_min   = row.get('Base Mínima','')
        nat_con    = str(row.get('Naturaleza Contraria','')).strip().upper()
        plazo      = str(row.get('Plazo','')).strip()

        # ── Código ──
        if vacia(row.get('Código','')):
            errores.append((fila,'Código','formato','❌ El código está vacío. Es obligatorio.','Campo vacío'))
        elif not es_entero(str(row.get('Código','')).replace(',','')):
            errores.append((fila,'Código','formato',f'❌ El código "{row.get("Código","")}" no es válido. Solo se permiten números enteros, sin puntos ni comas.','No numérico'))
        else:
            if len(cod) > 100:
                errores.append((fila,'Código','formato',f'❌ El código "{cod}" es muy largo (máximo 100 caracteres).','Longitud > 100'))
            if cod in codigos_vistos:
                errores.append((fila,'Código','formato',f'❌ El código "{cod}" está duplicado. Ya aparece en la fila {codigos_vistos[cod]}.','Código duplicado'))
            else:
                codigos_vistos[cod] = fila
            # Jerarquía: auxiliar debe tener un maestro padre
            if tipo == 'A':
                tiene_padre = any(cod.startswith(m) and cod != m for m in codigos_maestros)
                if not tiene_padre:
                    errores.append((fila,'Código','logica',f'❌ La cuenta auxiliar "{cod}" no tiene una cuenta maestra definida en la plantilla. Verifique que el maestro padre exista.','Auxiliar sin maestro padre'))

        # ── Descripción ──
        if vacia(desc):
            errores.append((fila,'Descripción','formato','❌ La descripción está vacía. Es obligatoria.','Campo vacío'))
        elif tiene_caracteres_especiales_desc(desc):
            errores.append((fila,'Descripción','formato',f'❌ La descripción "{desc[:30]}..." tiene caracteres no permitidos (< > {{ }} [ ]).','Caracteres especiales'))

        # ── Tipo ──
        if vacia(tipo):
            errores.append((fila,'Tipo','formato','❌ El Tipo está vacío. Debe ser M (Maestro) o A (Auxiliar).','Campo vacío'))
        elif tipo not in ('M','A'):
            errores.append((fila,'Tipo','formato',f'❌ El Tipo "{tipo}" no es válido. Solo se permite M (Maestro) o A (Auxiliar).','Valor distinto de M/A'))

        # ── Flags N/S ──
        for campo, val, nombre in [
            ('Requiere Centro Costo', req_cc, 'Requiere Centro Costo'),
            ('Requiere Tercero', req_ter, 'Requiere Tercero'),
            ('Requiere Base', req_base, 'Requiere Base'),
            ('Naturaleza Contraria', nat_con, 'Naturaleza Contraria'),
        ]:
            if not vacia(val) and val not in ('N','S'):
                errores.append((fila, campo, 'formato',
                    f'❌ El campo "{nombre}" tiene el valor "{val}". Solo se permite N (No) o S (Sí).',
                    f'Valor distinto de N/S'))

        # ── % ──
        if not vacia(pct):
            try:
                p = float(str(pct).replace(',','.'))
                if not (0 <= p <= 100):
                    errores.append((fila,'%','formato',f'❌ El porcentaje "{pct}" está fuera del rango. Debe ser un número entre 0 y 100.','Fuera de rango 0-100'))
            except:
                errores.append((fila,'%','formato',f'❌ El porcentaje "{pct}" no es un número válido.','No decimal'))

        # ── Base Mínima ──
        if not vacia(base_min) and not es_numerico(str(base_min)):
            errores.append((fila,'Base Mínima','formato',f'❌ La Base Mínima "{base_min}" no es un número válido.','No decimal'))

        # ── Plazo ──
        if not vacia(plazo):
            p_norm = str(int(float(plazo))) if es_numerico(plazo) else plazo
            if p_norm not in ('0','1','2'):
                errores.append((fila,'Plazo','formato',
                    f'❌ El Plazo "{plazo}" no es válido. Use: 0 (No aplica), 1 (Corto plazo) o 2 (Largo plazo).',
                    'Valor distinto de 0/1/2'))

        # ── Equivalencia (solo PUC Fiscal) ──
        if es_fiscal:
            equiv = normalizar_codigo(row.get('Equivalencia',''))
            equiv_raw = row.get('Equivalencia','')

            if tipo == 'M' and not vacia(equiv_raw):
                errores.append((fila,'Equivalencia','formato',
                    f'❌ La cuenta maestra "{cod}" no puede tener equivalencia. Solo las auxiliares pueden tener equivalencia.',
                    'Maestro con equivalencia'))

            if tipo == 'A' and not vacia(equiv_raw):
                if not es_entero(str(equiv_raw).replace(',','')):
                    errores.append((fila,'Equivalencia','formato',
                        f'❌ La equivalencia "{equiv_raw}" no es válida. Solo se permiten números enteros.',
                        'No numérico'))
                else:
                    if equiv in equivalencias_vistas:
                        errores.append((fila,'Equivalencia','formato',
                            f'❌ La equivalencia "{equiv}" ya está asignada a otra cuenta (fila {equivalencias_vistas[equiv]}). Cada cuenta del PUC Principal solo puede tener una equivalencia.',
                            'Equivalencia duplicada'))
                    else:
                        equivalencias_vistas[equiv] = fila
                    if codigos_principal and equiv not in codigos_principal:
                        errores.append((fila,'Equivalencia','logica',
                            f'❌ La equivalencia "{equiv}" no existe en el PUC Principal. Verifique que el código sea correcto.',
                            'No existe en PUC Principal'))

            if tipo == 'A' and vacia(equiv_raw):
                errores.append((fila,'Equivalencia','advertencia',
                    f'⚠️ La cuenta auxiliar "{cod}" no tiene equivalencia. Esto indica que es exclusiva de NIF. ¿Es correcto?',
                    'Auxiliar sin equivalencia — exclusiva NIF'))

    return errores


def validar_terceros(df, TIPOS_ID, BANCOS, CIUDADES_DEPTO, CIIU):
    """Valida plantilla de Terceros — Colombia (NIT)."""
    errores = []
    nits_vistos = {}
    cuentas_bancarias_vistas = {}

    for idx, row in df.iterrows():
        fila = idx + 2
        vals = [str(v).strip() for v in row.tolist() if not vacia(v)]
        if not vals: continue

        tipo_id   = str(row.get('Tipo identificación','')).strip().upper()
        num_id    = str(row.get('Número de identificación','')).strip()
        dv        = str(row.get('Dígito de verificación','')).strip()
        nat_jur   = str(row.get('Naturaleza Jurídica','')).strip().upper()
        razon_soc = str(row.get('Razon social - personas juridicas','')).strip()
        nombre1   = str(row.get('Nombre 1','')).strip()
        apellido1 = str(row.get('Apellido 1','')).strip()
        tipo_ter  = str(row.get('Tipo tercero','')).strip().upper()
        subtipo   = str(row.get('Subtipo','')).strip()
        ter_estado= str(row.get('TerEstado','')).strip()
        ciiu      = str(row.get('Actividad Económica Principal','')).strip()
        venc_fact = str(row.get('Vencimiento facturas','')).strip()
        telefono  = str(row.get('Telefono','')).strip()
        celular   = str(row.get('Celular','')).strip()
        ter_depto = str(row.get('TerDepartamento','')).strip()
        ter_ciudad= str(row.get('TerCiudad','')).strip()
        nom_cont  = str(row.get('Nombre contacto principal','')).strip()
        email_cont= str(row.get('Email contacto principal','')).strip()
        banco     = str(row.get('Banco','')).strip()
        tipo_cta  = str(row.get('Tipo Cuenta','')).strip()
        num_cta   = str(row.get('Número cuenta','')).strip()
        email_tes = str(row.get('Email Tesorería','')).strip()
        email_cert= str(row.get('Email certificados','')).strip()
        gr_contrib= str(row.get('Gran contribuyente','')).strip().upper()
        resp_iva  = str(row.get('Responsable de IVA','')).strip().upper()
        reg_esp   = str(row.get('Regimen especial','')).strip().upper()
        ob_fact   = str(row.get('Obligado a facturar','')).strip().upper()
        auto_ret  = str(row.get('Auto retenedor','')).strip().upper()
        auto_ica  = str(row.get('Auto retenedor ICA','')).strip().upper()
        ex_ret    = str(row.get('Exento Retención','')).strip().upper()
        dec_renta = str(row.get('Declarante de renta','')).strip().upper()
        prof_ind  = str(row.get('Profesional independiente','')).strip().upper()
        ag_ret_iva= str(row.get('Agente retenedor IVA','')).strip().upper()
        gr_ica_bog= str(row.get('Gran contribuyente de ICA Bogotá','')).strip().upper()
        ag_ret_ica= str(row.get('Agente retenedor de ICA','')).strip().upper()
        reg_simple= str(row.get('Regimen simple de tributacion','')).strip().upper()

        # T-01 Tipo identificación vacío
        if vacia(tipo_id):
            errores.append((fila,'Tipo identificación','formato','❌ El tipo de identificación está vacío. Es obligatorio.','Campo vacío'))
        # T-02 Tipo identificación no en catálogo
        elif tipo_id not in TIPOS_ID:
            errores.append((fila,'Tipo identificación','formato',
                f'❌ El tipo de identificación "{tipo_id}" no es válido. Valores permitidos: {", ".join(sorted(TIPOS_ID))}.',
                'No existe en catálogo'))

        # T-03 Número identificación vacío
        if vacia(num_id):
            errores.append((fila,'Número de identificación','formato','❌ El número de identificación está vacío. Es obligatorio.','Campo vacío'))
        else:
            # T-04 Duplicado
            if num_id in nits_vistos:
                errores.append((fila,'Número de identificación','formato',
                    f'❌ El número "{num_id}" está duplicado. Ya aparece en la fila {nits_vistos[num_id]}.',
                    'Valor duplicado'))
            else:
                nits_vistos[num_id] = fila
            # T-05 No numérico para NIT
            if tipo_id == 'NIT' and not es_entero(num_id):
                errores.append((fila,'Número de identificación','formato',
                    f'❌ El NIT "{num_id}" solo puede tener números, sin puntos, guiones ni letras.',
                    'No numérico'))
            # Dígito de verificación para NIT
            if tipo_id == 'NIT' and not vacia(dv):
                dv_calculado = calcular_dv(num_id)
                try:
                    dv_ingresado = int(float(dv))
                    if dv_calculado is not None and dv_ingresado != dv_calculado:
                        errores.append((fila,'Dígito de verificación','formato',
                            f'❌ El dígito de verificación "{dv}" del NIT {num_id} no es correcto. El valor esperado es {dv_calculado}.',
                            f'DV incorrecto. Esperado: {dv_calculado}'))
                except:
                    errores.append((fila,'Dígito de verificación','formato',
                        f'❌ El dígito de verificación "{dv}" no es un número válido.',
                        'No numérico'))

        # T-06/07 Naturaleza Jurídica
        if vacia(nat_jur):
            errores.append((fila,'Naturaleza Jurídica','formato',
                '❌ La Naturaleza Jurídica está vacía. Debe ser J (Jurídico) o N (Natural).','Campo vacío'))
        elif nat_jur not in ('J','N'):
            errores.append((fila,'Naturaleza Jurídica','formato',
                f'❌ La Naturaleza Jurídica "{nat_jur}" no es válida. Use J (Jurídico) o N (Natural).','Valor distinto de J/N'))
        else:
            # T-08 Jurídico sin razón social
            if nat_jur == 'J' and vacia(razon_soc):
                errores.append((fila,'Razon social - personas juridicas','formato',
                    '❌ Si la naturaleza es Jurídica (J), debe llenar la Razón Social.','J sin razón social'))
            # T-09 Natural sin nombre o apellido
            if nat_jur == 'N' and (vacia(nombre1) or vacia(apellido1)):
                errores.append((fila,'Nombre 1','formato',
                    '❌ Si la naturaleza es Natural (N), debe llenar Nombre 1 y Apellido 1.','N sin nombre/apellido'))

        # T-10/11 Tipo tercero
        if vacia(tipo_ter):
            errores.append((fila,'Tipo tercero','formato',
                '❌ El Tipo de tercero está vacío. Debe ser A (Cliente/Proveedor), C (Cliente), P (Proveedor) o E (Empleado).','Campo vacío'))
        elif tipo_ter not in ('A','C','P','E'):
            errores.append((fila,'Tipo tercero','formato',
                f'❌ El Tipo de tercero "{tipo_ter}" no es válido. Use A (Cliente/Proveedor), C (Cliente), P (Proveedor) o E (Empleado).','Valor distinto de A/C/P/E'))

        # Subtipo
        if not vacia(subtipo) and subtipo not in ('1','2','3','4','5'):
            errores.append((fila,'Subtipo','formato',
                f'❌ El Subtipo "{subtipo}" no es válido. Use: 1 (Contratos Mayores), 2 (Mano de Obra), 3 (Acreedores), 4 (Proveedores) o 5 (Fact. Título Valor).','Valor distinto de 1-5'))

        # TerEstado
        if not vacia(ter_estado) and ter_estado not in ('0','1'):
            errores.append((fila,'TerEstado','formato',
                f'❌ El Estado "{ter_estado}" no es válido. Use 0 (Activo) o 1 (Inactivo).','Valor distinto de 0/1'))

        # CIIU
        if not vacia(ciiu):
            try:
                ciiu_int = int(float(ciiu))
                if ciiu_int not in CIIU:
                    errores.append((fila,'Actividad Económica Principal','logica',
                        f'❌ El código CIIU "{ciiu}" no está registrado. Verifique el código de actividad económica.',
                        'CIIU no registrado'))
            except:
                errores.append((fila,'Actividad Económica Principal','formato',
                    f'❌ El código CIIU "{ciiu}" no es un número válido.','No numérico'))

        # T-13/14/15 TerCiudad
        if vacia(ter_ciudad):
            errores.append((fila,'TerCiudad','formato','❌ La ciudad está vacía. Es obligatoria.','Campo vacío'))
        elif not es_entero(ter_ciudad):
            errores.append((fila,'TerCiudad','formato',
                f'❌ El código de ciudad "{ter_ciudad}" solo puede tener números.','No numérico'))
        elif len(normalizar_ciudad(ter_ciudad)) > 3:
            errores.append((fila,'TerCiudad','formato',
                f'❌ El código de ciudad "{ter_ciudad}" es muy largo (máximo 3 dígitos).','Longitud > 3'))

        # T-16/17/18 TerDepartamento
        if vacia(ter_depto):
            errores.append((fila,'TerDepartamento','formato','❌ El departamento está vacío. Es obligatorio.','Campo vacío'))
        elif not es_entero(ter_depto):
            errores.append((fila,'TerDepartamento','formato',
                f'❌ El código de departamento "{ter_depto}" solo puede tener números.','No numérico'))
        elif len(normalizar_depto(ter_depto)) > 2:
            errores.append((fila,'TerDepartamento','formato',
                f'❌ El código de departamento "{ter_depto}" es muy largo (máximo 2 dígitos).','Longitud > 2'))
        else:
            # Combinación departamento + ciudad
            if es_entero(ter_ciudad) and es_entero(ter_depto):
                clave = (normalizar_depto(ter_depto), normalizar_ciudad(ter_ciudad))
                if clave not in CIUDADES_DEPTO:
                    errores.append((fila,'TerCiudad','logica',
                        f'❌ La combinación departamento "{ter_depto}" + ciudad "{ter_ciudad}" no existe. Verifique los códigos.',
                        'Combinación ciudad+departamento no registrada'))

        # Teléfono y Celular
        for campo, val in [('Telefono', telefono), ('Celular', celular)]:
            if not vacia(val):
                if len(val) > 15:
                    errores.append((fila, campo, 'formato',
                        f'❌ El {campo.lower()} "{val}" es muy largo (máximo 15 dígitos).','Longitud > 15'))
                elif re.search(r'[a-zA-Z]', val):
                    errores.append((fila, campo, 'formato',
                        f'❌ El {campo.lower()} "{val}" tiene letras. Solo se permiten números.','Alfanumérico'))

        # Nombre contacto principal
        if not vacia(nom_cont) and len(nom_cont) > 100:
            errores.append((fila,'Nombre contacto principal','formato',
                f'❌ El nombre del contacto es muy largo (máximo 100 caracteres).','Longitud > 100'))

        # Emails
        for campo, val in [
            ('Email contacto principal', email_cont),
            ('Email Tesorería', email_tes),
            ('Email certificados', email_cert),
        ]:
            if not vacia(val):
                if len(val) > 100:
                    errores.append((fila, campo, 'formato',
                        f'❌ El correo "{val[:30]}..." es muy largo (máximo 100 caracteres).','Longitud > 100'))
                elif not es_email_valido(val):
                    errores.append((fila, campo, 'formato',
                        f'❌ El correo "{val}" no tiene un formato válido. Ejemplo correcto: nombre@empresa.com','Formato inválido'))

        # Banco + Tipo Cuenta + Número cuenta — deben estar los 3 o ninguno
        tiene_banco = not vacia(banco)
        tiene_tipo  = not vacia(tipo_cta)
        tiene_num   = not vacia(num_cta)
        if any([tiene_banco, tiene_tipo, tiene_num]) and not all([tiene_banco, tiene_tipo, tiene_num]):
            errores.append((fila,'Número cuenta','formato',
                '❌ Si llena datos bancarios debe completar los 3 campos: Banco, Tipo de Cuenta y Número de Cuenta.',
                'Datos bancarios incompletos'))
        if tiene_banco:
            banco_norm = str(banco).strip().zfill(2)
            if banco_norm not in BANCOS:
                errores.append((fila,'Banco','logica',
                    f'❌ El código de banco "{banco}" no está registrado. Revise la hoja BANCOS de la plantilla para ver los códigos válidos.',
                    'Banco no registrado'))
        if tiene_tipo and tipo_cta not in ('1','2','5'):
            errores.append((fila,'Tipo Cuenta','formato',
                f'❌ El Tipo de Cuenta "{tipo_cta}" no es válido. Use 1 (Corriente), 2 (Ahorros) o 5 (Crédito Rotativo).','Valor distinto de 1/2/5'))
        if all([tiene_banco, tiene_tipo, tiene_num]):
            clave_cta = f"{banco}_{tipo_cta}_{num_cta}"
            if clave_cta in cuentas_bancarias_vistas:
                errores.append((fila,'Número cuenta','formato',
                    f'❌ La cuenta bancaria ya está registrada en la fila {cuentas_bancarias_vistas[clave_cta]}. No puede repetirse.',
                    'Cuenta bancaria duplicada'))
            else:
                cuentas_bancarias_vistas[clave_cta] = fila

        # Email Tesorería requiere datos bancarios completos
        if not vacia(email_tes) and not all([tiene_banco, tiene_tipo, tiene_num]):
            errores.append((fila,'Email Tesorería','formato',
                '❌ Si llena el Email de Tesorería, debe completar también los datos bancarios (Banco, Tipo de Cuenta y Número de Cuenta).',
                'Email Tesorería sin datos bancarios'))

        # Flags N/S
        flags_ns = [
            ('Gran contribuyente', gr_contrib),
            ('Responsable de IVA', resp_iva),
            ('Regimen especial', reg_esp),
            ('Obligado a facturar', ob_fact),
            ('Auto retenedor', auto_ret),
            ('Auto retenedor ICA', auto_ica),
            ('Exento Retención', ex_ret),
            ('Declarante de renta', dec_renta),
            ('Profesional independiente', prof_ind),
            ('Agente retenedor IVA', ag_ret_iva),
            ('Gran contribuyente de ICA Bogotá', gr_ica_bog),
            ('Regimen simple de tributacion', reg_simple),
        ]
        for campo, val in flags_ns:
            if not vacia(val) and val not in ('N','S'):
                errores.append((fila, campo, 'formato',
                    f'❌ El campo "{campo}" tiene el valor "{val}". Solo se permite N (No) o S (Sí).','Valor distinto de N/S'))

        # Agente retenedor de ICA
        if vacia(ag_ret_ica):
            errores.append((fila,'Agente retenedor de ICA','formato',
                '❌ El campo Agente retenedor de ICA está vacío. Use AR (Agente Retenedor), EP (Entidad Pública) o NA (No Aplica).',
                'Campo vacío'))
        elif ag_ret_ica not in ('AR','EP','NA'):
            errores.append((fila,'Agente retenedor de ICA','formato',
                f'❌ El valor "{ag_ret_ica}" no es válido. Use AR (Agente Retenedor), EP (Entidad Pública) o NA (No Aplica).',
                'Valor distinto de AR/EP/NA'))

        # Vencimiento facturas
        if not vacia(venc_fact) and not es_entero(venc_fact):
            errores.append((fila,'Vencimiento facturas','formato',
                f'❌ El vencimiento "{venc_fact}" no es válido. Debe ser un número entero.','No numérico'))

    return errores


def validar_centros_costos(df, CIUDADES_DEPTO):
    """Valida plantilla de Centros de Costos."""
    errores = []
    codigos_vistos = {}
    codigos_maestros = set()

    # Primer paso: recolectar maestros para validar jerarquía
    for idx, row in df.iterrows():
        cod  = normalizar_codigo(row.get('Código',''))
        tipo = str(row.get('Tipo','')).strip().upper()
        if cod and tipo == 'M':
            codigos_maestros.add(cod)

    for idx, row in df.iterrows():
        fila = idx + 2
        vals = [str(v).strip() for v in row.tolist() if not vacia(v)]
        if not vals: continue

        cod      = normalizar_codigo(row.get('Código',''))
        desc     = str(row.get('Descripción','')).strip()
        tipo     = str(row.get('Tipo','')).strip().upper()
        depto    = str(row.get('Codigo Departamento','')).strip()
        ciudad   = str(row.get('Codigo Ciudad','')).strip()
        mandante = str(row.get('Mandante','')).strip()
        sucursal = str(row.get('Sucursal Administrativa','')).strip()

        # CC-01 Código vacío
        if vacia(row.get('Código','')):
            errores.append((fila,'Código','formato','❌ El código está vacío. Es obligatorio.','Campo vacío'))
        elif not es_entero(str(row.get('Código','')).replace(',','')):
            errores.append((fila,'Código','formato',
                f'❌ El código "{row.get("Código","")}" no es válido. Solo se permiten números enteros.','No numérico'))
        else:
            # CC-03 Duplicado
            if cod in codigos_vistos:
                errores.append((fila,'Código','formato',
                    f'❌ El código "{cod}" está duplicado. Ya aparece en la fila {codigos_vistos[cod]}.','Código duplicado'))
            else:
                codigos_vistos[cod] = fila
            # CC-04 Jerarquía
            if tipo == 'A':
                tiene_padre = any(cod.startswith(m) and cod != m for m in codigos_maestros)
                if not tiene_padre:
                    errores.append((fila,'Código','logica',
                        f'❌ El centro de costos auxiliar "{cod}" no tiene un maestro padre definido. Verifique la estructura.',
                        'Auxiliar sin maestro padre'))

        # CC-05 Maestro con sucursal
        if tipo == 'M' and not vacia(sucursal):
            errores.append((fila,'Sucursal Administrativa','formato',
                '❌ Los centros de costo tipo Maestro no pueden tener Sucursal Administrativa.','Maestro con sucursal'))

        # CC-06 Ciudad sin departamento o viceversa
        tiene_depto  = not vacia(depto)
        tiene_ciudad = not vacia(ciudad)
        if tiene_depto != tiene_ciudad:
            errores.append((fila,'Codigo Departamento','formato',
                '❌ Si llena Ciudad debe llenar también Departamento, y viceversa. No puede tener uno sin el otro.',
                'Ciudad sin departamento o viceversa'))
        elif tiene_depto and tiene_ciudad:
            if re.search(r'[^0-9]', depto):
                errores.append((fila,'Codigo Departamento','formato',
                    f'❌ El código de departamento "{depto}" tiene caracteres no permitidos. Solo se permiten números.',
                    'Caracteres especiales'))
            if re.search(r'[^0-9]', ciudad):
                errores.append((fila,'Codigo Ciudad','formato',
                    f'❌ El código de ciudad "{ciudad}" tiene caracteres no permitidos. Solo se permiten números.',
                    'Caracteres especiales'))
            if es_entero(depto) and es_entero(ciudad):
                clave = (normalizar_depto(depto), normalizar_ciudad(ciudad))
                if clave not in CIUDADES_DEPTO:
                    errores.append((fila,'Codigo Ciudad','logica',
                        f'❌ La combinación departamento "{depto}" + ciudad "{ciudad}" no existe en el catálogo.',
                        'Combinación ciudad+departamento no registrada'))

        # CC-07/08 Descripción
        if vacia(desc):
            errores.append((fila,'Descripción','formato','❌ La descripción está vacía. Es obligatoria.','Campo vacío'))
        elif len(desc) > 50:
            errores.append((fila,'Descripción','formato',
                f'❌ La descripción "{desc[:30]}..." es muy larga (máximo 50 caracteres). Tiene {len(desc)}.','Longitud > 50'))

        # CC-09/10 Tipo
        if vacia(tipo):
            errores.append((fila,'Tipo','formato',
                '❌ El Tipo está vacío. Debe ser M (Maestro) o A (Auxiliar).','Campo vacío'))
        elif tipo not in ('M','A'):
            errores.append((fila,'Tipo','formato',
                f'❌ El Tipo "{tipo}" no es válido. Use M (Maestro) o A (Auxiliar).','Valor distinto de M/A'))

        # CC-13 Mandante
        if not vacia(mandante) and not es_entero(mandante):
            errores.append((fila,'Mandante','formato',
                f'❌ El Mandante "{mandante}" no es válido. Solo se permiten números enteros.','No numérico'))

        # CC-14 Sucursal Administrativa
        if not vacia(sucursal) and not es_entero(sucursal):
            errores.append((fila,'Sucursal Administrativa','formato',
                f'❌ La Sucursal "{sucursal}" no es válida. Solo se permiten números enteros.','No numérico'))

    return errores


