C_DARK = "#1B3A6B"; C_MID = "#4A7FB5"
C_GREEN = "#16A34A"; C_RED = "#DC2626"; C_ORANGE = "#D97706"

def render_resultado_etapa1(errores, nombre, archivo_orig=None, df_orig=None):
    """Renderiza resultado de validación con UX clara."""
    errs_fila     = [e for e in errores if e[0] is not None and e[2] != 'advertencia']
    advertencias  = [e for e in errores if e[2] == 'advertencia']
    total_errores = len(errs_fila)

    if total_errores == 0 and len(advertencias) == 0:
        st.markdown(f'<div style="background:#F0FDF4;border:1px solid #BBF7D0;border-left:4px solid {C_GREEN};border-radius:8px;padding:14px 18px;font-size:13px;color:#14532D">✅ <b>¡{nombre} lista!</b> No se encontraron errores. Puede continuar con la importación.</div>', unsafe_allow_html=True)
        return

    if total_errores > 0:
        st.markdown(f'<div style="background:#FEF2F2;border:1px solid #FECACA;border-left:4px solid {C_RED};border-radius:8px;padding:12px 16px;font-size:13px;color:#7F1D1D">❌ Se encontraron <b>{total_errores} error(es)</b> que deben corregirse antes de importar.</div>', unsafe_allow_html=True)

    if len(advertencias) > 0:
        st.markdown(f'<div style="background:#FFFBEB;border:1px solid #FDE68A;border-left:4px solid {C_ORANGE};border-radius:8px;padding:12px 16px;font-size:13px;color:#78350F;margin-top:6px">⚠️ <b>{len(advertencias)} advertencia(s)</b> que debe revisar.</div>', unsafe_allow_html=True)

    if total_errores == 0 and len(advertencias) > 0:
        st.markdown(f'<div style="background:#F0FDF4;border:1px solid #BBF7D0;border-left:4px solid {C_GREEN};border-radius:8px;padding:14px 18px;font-size:13px;color:#14532D;margin-top:6px">✅ No hay errores bloqueantes. Revise las advertencias antes de continuar.</div>', unsafe_allow_html=True)

    if total_errores > 0:
        # Agrupar por columna
        st.markdown("**📋 Detalle de errores por columna:**")
        cols_con_errores = sorted(set(e[1] for e in errs_fila))
        for col in cols_con_errores:
            errs_col = [e for e in errs_fila if e[1] == col]
            tag = {'formato':'🟡 FORMATO','logica':'🟢 LÓGICA'}.get(errs_col[0][2],'🔵')
            with st.expander(f"{tag} {col} — {len(errs_col)} error(es)", expanded=len(errs_col) <= 3):
                for e in errs_col:
                    fila_txt = f"Fila {e[0]}"
                    st.markdown(f'<div style="background:white;border:1px solid #E2E8F0;border-radius:6px;padding:8px 12px;margin:3px 0;font-size:13px"><b style="color:{C_MID}">{fila_txt}</b> &nbsp; {e[3]}</div>', unsafe_allow_html=True)

    if len(advertencias) > 0:
        st.markdown("**⚠️ Advertencias:**")
        for e in advertencias:
            fila_txt = f"Fila {e[0]}" if e[0] else "General"
            st.markdown(f'<div style="background:#FFFBEB;border:1px solid #FDE68A;border-radius:6px;padding:8px 12px;margin:3px 0;font-size:13px"><b style="color:{C_ORANGE}">{fila_txt}</b> &nbsp; {e[3]}</div>', unsafe_allow_html=True)

    # Botones de descarga
    if total_errores > 0 and archivo_orig and df_orig is not None:
        plantilla_marcada = marcar_errores_excel(archivo_orig, errs_fila, df_orig)
        if plantilla_marcada:
            st.download_button(
                label=f"🔴 Descargar {nombre} con errores marcados en rojo",
                data=plantilla_marcada,
                file_name=f"CORREGIR_{nombre.replace(' ','_')}_{datetime.today().strftime('%Y%m%d')}.xlsx",
                mime="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
                key=f"btn_marcada_{nombre}"
            )
            st.markdown(f'<div style="background:#EFF6FF;border:1px solid #BFDBFE;border-left:4px solid {C_MID};border-radius:8px;padding:11px 15px;font-size:13px;color:{C_DARK};margin-top:4px">💡 Abra el archivo descargado en Excel, corrija las celdas <b>resaltadas en rojo</b> y vuelva a cargarlo aquí para verificar.</div>', unsafe_allow_html=True)



